func (r *PackSourceResource) ImportState(ctx context.Context, req resource.ImportStateRequest, resp *resource.ImportStateResponse) {
	dec := json.NewDecoder(bytes.NewReader([]byte(req.ID)))
	dec.DisallowUnknownFields()
	var data struct {
		GroupID string `json:"group_id"`
		ID      string `json:"id"`
		Pack    string `json:"pack"`
	}
	if err := dec.Decode(&data); err != nil {
		resp.Diagnostics.AddError("Invalid ID", `The import ID is not valid. It is expected to be a JSON object string with the required path parameters: `+err.Error())
		return
	}
	if data.GroupID == "" {
		resp.Diagnostics.AddError("Missing required field", `The field group_id is required but was not found in the json encoded ID.`)
		return
	}
	if data.ID == "" {
		resp.Diagnostics.AddError("Missing required field", `The field id is required but was not found in the json encoded ID.`)
		return
	}
	if data.Pack == "" {
		resp.Diagnostics.AddError("Missing required field", `The field pack is required but was not found in the json encoded ID.`)
		return
	}
	var model PackSourceModel
	model.GroupID = types.StringValue(data.GroupID)
	resp.Diagnostics.Append(resp.State.SetAttribute(ctx, path.Root("group_id"), data.GroupID)...)
	model.ID = types.StringValue(data.ID)
	resp.Diagnostics.Append(resp.State.SetAttribute(ctx, path.Root("id"), data.ID)...)
	model.Pack = types.StringValue(data.Pack)
	resp.Diagnostics.Append(resp.State.SetAttribute(ctx, path.Root("pack"), data.Pack)...)
	if resp.Diagnostics.HasError() {
		return
	}
	apiModel, err := r.api.Read(ctx, model)
	if err != nil {
		resp.Diagnostics.AddError("failure to invoke API", err.Error())
		return
	}
	applyPackSourceAPIToState(apiModel, &model, false, false)
	normalizePackSourceRootInputEmptyLists(&model)
	resp.Diagnostics.Append(resp.State.Set(ctx, &model)...)
}

func isPackSourceImportState(state *PackSourceModel) bool {
	if state == nil {
		return false
	}
	return false
}

